#include <bits/stdc++.h>
using namespace std;
bool check(int n){
    int sum1=0,sum2=0;
    int tmp=n;
    while(tmp){
        if(tmp%2==1)sum1++;
        else sum2++;
        tmp/=2;
    }
    return sum1>sum2;
}
int main(){
    int n,a=0,b=0;
    cin>>n;
    for(int i=1;i<=n;i++){
        if(check(i))a++;
        else b++;
    }
    cout<<a<<' '<<b;
    return 0;
}
